/*
 * test/fixtures/quic_test_pki_reload.h
 *
 * Second test PKI fixture, used to verify hot-reload semantics.  Same
 * shape as quic_test_pki.h (DER cert + PKCS#8 PEM key) but a distinct
 * keypair so a "reload took effect" assertion is bytes-level
 * meaningful.
 *
 *   openssl ecparam -name prime256v1 -genkey -noout -out k.pem
 *   openssl req -x509 -key k.pem -out c.pem -days 3650 \
 *       -subj "/CN=quic-reload-test.n00b.local"
 *   openssl pkcs8 -in k.pem -topk8 -nocrypt -out kpkcs8.pem
 *   openssl x509 -in c.pem -outform DER -out c.der
 *
 * Self-signed; test-only.  Re-generate when these expire (2036).
 */
#pragma once

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

static const char n00b_quic_reload_key_pem[] =
    "-----BEGIN PRIVATE KEY-----\n"
    "MIGHAgEAMBMGByqGSM49AgEGCCqGSM49AwEHBG0wawIBAQQgEhcU8XCHMQJb1bOK\n"
    "c5MZgOOzHhXn8ltK39sOzXhGYqyhRANCAAQV3NZ3gHjEfjLcIafQiz18Wx0rTsww\n"
    "WeF3BCjZT2dy99sNBLK5TVs/ZWUxrPQ5EHs3tLHL+nbX/ASRZqttz+XU\n"
    "-----END PRIVATE KEY-----\n";

static const size_t n00b_quic_reload_key_pem_len =
    sizeof(n00b_quic_reload_key_pem) - 1;

/* Write the reload key PEM to a fresh tempfile.  Caller unlinks + frees. */
static inline char *
n00b_quic_reload_write_key_pem(void)
{
    char tmpl[] = "/tmp/n00b_quic_reload_keyXXXXXX.pem";
    int  fd = mkstemps(tmpl, 4);
    if (fd < 0) return NULL;

    ssize_t expected = (ssize_t)n00b_quic_reload_key_pem_len;
    ssize_t written  = write(fd, n00b_quic_reload_key_pem,
                             n00b_quic_reload_key_pem_len);
    close(fd);
    if (written != expected) {
        unlink(tmpl);
        return NULL;
    }
    char *out = (char *)malloc(strlen(tmpl) + 1);
    if (!out) { unlink(tmpl); return NULL; }
    memcpy(out, tmpl, strlen(tmpl) + 1);
    return out;
}

